package org.jewzaam.cruiseweather.data.repository

import com.google.common.truth.Truth.assertThat
import io.mockk.coEvery
import io.mockk.mockk
import kotlinx.coroutines.test.runTest
import org.jewzaam.cruiseweather.data.remote.OpenMeteoApi
import org.jewzaam.cruiseweather.data.remote.dto.GeocodingResponse
import org.jewzaam.cruiseweather.geocodingResult
import org.junit.Before
import org.junit.Test

class GeocodingRepositoryTest {

    private val api = mockk<OpenMeteoApi>()
    private lateinit var repository: GeocodingRepository

    @Before
    fun setUp() {
        repository = GeocodingRepository(api = api)
    }

    @Test
    fun `geocode builds display name from name, admin1, and country`() = runTest {
        val result = geocodingResult(name = "Miami", admin1 = "Florida", country = "United States")
        coEvery { api.geocode(any(), any()) } returns GeocodingResponse(results = listOf(result))

        val candidates = repository.geocode("Miami").getOrThrow()

        assertThat(candidates).hasSize(1)
        assertThat(candidates[0].displayName).isEqualTo("Miami, Florida, United States")
    }

    @Test
    fun `geocode handles null admin1 and country in display name`() = runTest {
        val result = geocodingResult(name = "SomePlace", admin1 = null, country = null)
        coEvery { api.geocode(any(), any()) } returns GeocodingResponse(results = listOf(result))

        val candidates = repository.geocode("SomePlace").getOrThrow()

        assertThat(candidates[0].displayName).isEqualTo("SomePlace")
    }

    @Test
    fun `geocode filters out airport and station feature codes`() = runTest {
        val city = geocodingResult(id = 1, name = "Miami", featureCode = "PPL")
        val airport = geocodingResult(id = 2, name = "Miami Airport", featureCode = "AIRP")
        val station = geocodingResult(id = 3, name = "Miami Station", featureCode = "RSTN")
        coEvery { api.geocode(any(), any()) } returns GeocodingResponse(results = listOf(city, airport, station))

        val candidates = repository.geocode("Miami").getOrThrow()

        assertThat(candidates).hasSize(1)
        assertThat(candidates[0].displayName).contains("Miami")
        assertThat(candidates.map { it.id }).containsExactly(1L)
    }

    @Test
    fun `geocode falls back to unfiltered when filtering removes all results`() = runTest {
        val airport = geocodingResult(id = 1, name = "Airport City", featureCode = "AIRP")
        coEvery { api.geocode(any(), any()) } returns GeocodingResponse(results = listOf(airport))

        val candidates = repository.geocode("Airport City").getOrThrow()

        assertThat(candidates).hasSize(1)
        assertThat(candidates[0].id).isEqualTo(1L)
    }

    @Test
    fun `geocode limits results to 5 candidates`() = runTest {
        val results = (1..10L).map { i ->
            geocodingResult(id = i, name = "City$i", featureCode = "PPL")
        }
        coEvery { api.geocode(any(), any()) } returns GeocodingResponse(results = results)

        val candidates = repository.geocode("City").getOrThrow()

        assertThat(candidates).hasSize(5)
    }

    @Test
    fun `geocode returns empty list when results is null`() = runTest {
        coEvery { api.geocode(any(), any()) } returns GeocodingResponse(results = null)

        val candidates = repository.geocode("Nothing").getOrThrow()

        assertThat(candidates).isEmpty()
    }

    @Test
    fun `geocode maps latitude and longitude correctly`() = runTest {
        val result = geocodingResult(latitude = 25.77, longitude = -80.19)
        coEvery { api.geocode(any(), any()) } returns GeocodingResponse(results = listOf(result))

        val candidates = repository.geocode("Miami").getOrThrow()

        assertThat(candidates[0].latitude).isEqualTo(25.77)
        assertThat(candidates[0].longitude).isEqualTo(-80.19)
    }

    @Test
    fun `geocode returns failure on API exception`() = runTest {
        coEvery { api.geocode(any(), any()) } throws RuntimeException("Network error")

        val result = repository.geocode("fail")

        assertThat(result.isFailure).isTrue()
        assertThat(result.exceptionOrNull()?.message).isEqualTo("Network error")
    }
}
